import{_ as a,C as r,o as i,c as s,j as t,a as d,E as l,ag as c}from"./chunks/framework.HG0H2VLS.js";const v=JSON.parse('{"title":"SystemRole","description":"","frontmatter":{},"headers":[],"relativePath":"templates/system-role.md","filePath":"templates/system-role.md"}'),n={name:"templates/system-role.md"};function h(m,e,p,u,b,g){const o=r("ComponentDemo");return i(),s("div",null,[e[0]||(e[0]=t("hr",null,null,-1)),e[1]||(e[1]=t("h2",{id:"title-systemrole",tabindex:"-1"},[d("title: SystemRole "),t("a",{class:"header-anchor",href:"#title-systemrole","aria-label":'Permalink to "title: SystemRole"'},"​")],-1)),e[2]||(e[2]=t("h1",{id:"systemrole",tabindex:"-1"},[d("SystemRole "),t("a",{class:"header-anchor",href:"#systemrole","aria-label":'Permalink to "SystemRole"'},"​")],-1)),e[3]||(e[3]=t("blockquote",null,[t("p",null,"Default (full modal, blurred overlay) + Minimised (400px panel, draggable, left-edge resizable) + Mobile variant (176:3242): full-viewport CSS-only layout at <=767px, no resize/drag")],-1)),l(o,{src:"/demos/src/templates/SystemRole/SystemRole.html"}),e[4]||(e[4]=c('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>SystemRole is a <strong>modal editor for the AI assistant&#39;s system prompt</strong> — the instruction text that defines how the LLM behaves (tone, rules, escalation framework, etc.). It&#39;s accessed from the ChatHeader admin controls in the AiChat template.</p><p>The modal has two panels:</p><ul><li><strong>Prompt textarea</strong> (left in Default, top in Minimised) — editable text containing the current system prompt</li><li><strong>Sidebar</strong> (right in Default, below in Minimised) — two helper panels: VersionHistory and PromptTemplates</li></ul><p>Uses <code>data-surface=&quot;chat&quot;</code> for the chat-context token palette.</p><h3 id="layout-modes" tabindex="-1">Layout modes <a class="header-anchor" href="#layout-modes" aria-label="Permalink to &quot;Layout modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Trigger</th><th>Layout</th></tr></thead><tbody><tr><td>Default</td><td>Full-screen modal</td><td>Side-by-side (prompt + sidebar), blurred backdrop overlay</td></tr><tr><td>Minimised</td><td>Minimize button / <code>&lt;940px</code> container query</td><td>Stacked (prompt above sidebar), floating draggable/resizable panel</td></tr><tr><td>Mobile</td><td><code>@media (max-width: 767px)</code></td><td>Full-viewport, stacked, no drag/resize, no overlay</td></tr></tbody></table><hr><h2 id="version-history-behaviour" tabindex="-1">Version History behaviour <a class="header-anchor" href="#version-history-behaviour" aria-label="Permalink to &quot;Version History behaviour&quot;">​</a></h2><p>Shows previously saved prompt versions, each with an author avatar and timestamp. The live (current) version starts <strong>selected</strong> with a green check circle.</p><h3 id="interaction-model-—-radio-toggle" tabindex="-1">Interaction model — radio toggle <a class="header-anchor" href="#interaction-model-—-radio-toggle" aria-label="Permalink to &quot;Interaction model — radio toggle&quot;">​</a></h3><ul><li><strong>Click a row</strong> → selects it (green check replaces avatar portrait), loads that row&#39;s <code>data-prompt</code> into the textarea, marks prompt as &quot;template-linked&quot; (border highlights to <code>--ai-border-primary</code>)</li><li><strong>Click the same row again</strong> → deselects it, reverts textarea to last saved value</li><li><strong>Click a different row</strong> → deselects previous, selects new one</li><li><strong>Selecting a VH row clears any active Prompt Template</strong> (mutual exclusivity)</li></ul><h3 id="visual-states" tabindex="-1">Visual states <a class="header-anchor" href="#visual-states" aria-label="Permalink to &quot;Visual states&quot;">​</a></h3><table tabindex="0"><thead><tr><th>State</th><th>Background</th><th>Border</th><th>Avatar</th></tr></thead><tbody><tr><td>Default (unselected)</td><td>transparent</td><td>transparent</td><td>Portrait image, <code>--ai-surface-elevated-1</code> ring</td></tr><tr><td>Hover</td><td><code>--ai-surface-elevated-1</code></td><td><code>--ai-border-invert</code></td><td>Portrait image</td></tr><tr><td>Selected</td><td><code>--ai-surface-elevated-1</code></td><td><code>--ai-border-invert</code></td><td>Green check circle (<code>--ai-surface-success</code>)</td></tr><tr><td>Live</td><td><code>--ai-surface-elevated-2</code></td><td>none</td><td>Portrait image</td></tr><tr><td>Selected &amp; Live</td><td><code>--ai-surface-elevated-2</code></td><td>none</td><td>Green check circle, wider gap (<code>--ai-spacing-5</code>)</td></tr></tbody></table><h3 id="live-row" tabindex="-1">Live row <a class="header-anchor" href="#live-row" aria-label="Permalink to &quot;Live row&quot;">​</a></h3><ul><li>Starts pre-selected with check icon on initial load</li><li><code>data-portrait-src</code> stores the original portrait URL for restoration on deselect</li><li>The avatar swap is handled by JS: portrait <code>&lt;img&gt;</code> is replaced with <code>&lt;i data-lucide=&quot;check&quot;&gt;</code> on select, and restored on deselect</li></ul><h3 id="expand-collapse" tabindex="-1">Expand/collapse <a class="header-anchor" href="#expand-collapse" aria-label="Permalink to &quot;Expand/collapse&quot;">​</a></h3><p>Footer toggle (&quot;Show older&quot; / &quot;Show less&quot;) reveals additional rows beyond the initial 5 visible.</p><hr><h2 id="prompt-templates-behaviour" tabindex="-1">Prompt Templates behaviour <a class="header-anchor" href="#prompt-templates-behaviour" aria-label="Permalink to &quot;Prompt Templates behaviour&quot;">​</a></h2><p>Shows reusable prompt presets. Each item has an icon, title, and expandable description.</p><h3 id="interaction-model-—-radio-toggle-with-accordion" tabindex="-1">Interaction model — radio toggle with accordion <a class="header-anchor" href="#interaction-model-—-radio-toggle-with-accordion" aria-label="Permalink to &quot;Interaction model — radio toggle with accordion&quot;">​</a></h3><ul><li><strong>Click an item</strong> → selects it (border changes to <code>--ai-border-invert</code>), loads the item&#39;s description text into the textarea, marks prompt as &quot;template-linked&quot;</li><li><strong>Click the same item again</strong> → deselects, reverts textarea to saved value</li><li><strong>Click a different item</strong> → deselects previous, selects new</li><li><strong>Selecting a template clears any active VH row</strong> (mutual exclusivity)</li></ul><h3 id="chevron-accordion" tabindex="-1">Chevron accordion <a class="header-anchor" href="#chevron-accordion" aria-label="Permalink to &quot;Chevron accordion&quot;">​</a></h3><ul><li>Click the chevron → expands that item&#39;s description panel (chevron rotates 90deg)</li><li>Only one item expanded at a time — others auto-collapse</li><li>Chevron click does NOT trigger selection (<code>stopPropagation</code>)</li><li>Clicking outside the panel collapses any expanded item</li></ul><hr><h2 id="mutual-exclusivity" tabindex="-1">Mutual exclusivity <a class="header-anchor" href="#mutual-exclusivity" aria-label="Permalink to &quot;Mutual exclusivity&quot;">​</a></h2><p>Version History and Prompt Templates are <strong>mutually exclusive</strong>. Selecting from one always deselects the other. The textarea always reflects a single source — either a historical version or a template, never both.</p><hr><h2 id="dirty-state" tabindex="-1">Dirty state <a class="header-anchor" href="#dirty-state" aria-label="Permalink to &quot;Dirty state&quot;">​</a></h2><p>Any change to the textarea (including loads from VH/PT) triggers dirty detection:</p><table tabindex="0"><thead><tr><th>State</th><th>Header buttons shown</th><th>Prompt border</th></tr></thead><tbody><tr><td>Clean</td><td>&quot;Make Live&quot; (disabled)</td><td><code>--ai-border-secondary</code> (default)</td></tr><tr><td>Dirty</td><td>&quot;Discard Changes&quot; + &quot;Save&quot;</td><td><code>--ai-border-secondary</code> (default)</td></tr><tr><td>Template-linked</td><td>Per dirty state above</td><td><code>--ai-border-primary</code> (highlighted via <code>.system-role__prompt--template-linked</code>)</td></tr></tbody></table><ul><li><strong>Discard</strong> → reverts textarea to last saved value, clears dirty + template-linked state</li><li><strong>Save</strong> → updates saved value, clears dirty state</li></ul><hr><h2 id="js-behaviors" tabindex="-1">JS Behaviors <a class="header-anchor" href="#js-behaviors" aria-label="Permalink to &quot;JS Behaviors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Behavior</th><th>Trigger</th><th>Effect</th></tr></thead><tbody><tr><td>Dirty detection</td><td><code>textarea</code> <code>input</code> event</td><td>Toggles <code>.system-role--dirty</code>; Discard/Save buttons appear</td></tr><tr><td>Discard</td><td>Click <code>.system-role__btn-discard</code></td><td>Restores <code>savedValue</code> to textarea, removes dirty state</td></tr><tr><td>Save</td><td>Click <code>.system-role__btn-save</code></td><td>Updates <code>savedValue</code>, removes dirty state</td></tr><tr><td>Minimise</td><td>Click <code>.system-role__minimize-btn</code></td><td>Adds <code>--minimised</code> + <code>data-layout=&quot;minimised&quot;</code>, hides overlay, positions top-right</td></tr><tr><td>Maximise</td><td>Click <code>.system-role__maximize-btn</code></td><td>Removes <code>--minimised</code> + <code>data-layout</code>, clears inline styles, restores overlay</td></tr><tr><td>Close</td><td>Click <code>.system-role__close-btn</code></td><td>Removes <code>--open</code>, hides overlay, shows &quot;Open&quot; button</td></tr><tr><td>Re-open</td><td>Click <code>#openBtn</code></td><td>Adds <code>--open</code>, restores overlay (if Default mode)</td></tr><tr><td>Drag</td><td>Mousedown on <code>.system-role__top</code> (Minimised only, not on buttons)</td><td>Updates <code>left</code>/<code>top</code> inline styles; suppresses transition with <code>--no-transition</code></td></tr><tr><td>Resize (width)</td><td>Mousedown on <code>.system-role__resize-handle</code> (Minimised only)</td><td>Updates <code>width</code> + <code>left</code> inline styles; right edge stays fixed; min-width 400px</td></tr><tr><td>Minimise heights</td><td>Click <code>.system-role__minimize-btn</code></td><td>Sets <code>modal.style.height = 75vh</code>; sets <code>textarea.style.height = panelHeight/3</code></td></tr><tr><td>Textarea resize</td><td>Mousedown on <code>.system-role__textarea-resize-handle</code> (Minimised only)</td><td>Drags bottom of prompt area; updates <code>textarea.style.height</code>; min 80px</td></tr><tr><td>Panel height resize</td><td>Mousedown on <code>.system-role__resize-handle-bottom</code> (Minimised only)</td><td>Drags bottom edge of panel; updates <code>modal.style.height</code>; min 200px, max = viewport bottom minus 16px</td></tr></tbody></table><h2 id="minimised-layout-details" tabindex="-1">Minimised Layout Details <a class="header-anchor" href="#minimised-layout-details" aria-label="Permalink to &quot;Minimised Layout Details&quot;">​</a></h2><p>Minimised mode is triggered by:</p><ol><li><code>.system-role--minimised</code> CSS modifier (layout + size overrides)</li><li><code>data-layout=&quot;minimised&quot;</code> attribute (activates <code>tokens-minimised.css</code> — shrinks <code>--ai-font-fluid-*</code> tokens)</li></ol><p>The header in Minimised mode mirrors the <code>@media (max-width: 767px)</code> layout in <code>Header.css</code>, but applied via a CSS class selector rather than a media query — allowing the compact layout in a deliberate side-panel context independent of screen width.</p><h2 id="contextual-override-case-b" tabindex="-1">Contextual Override (Case B) <a class="header-anchor" href="#contextual-override-case-b" aria-label="Permalink to &quot;Contextual Override (Case B)&quot;">​</a></h2><p>The Header in the Minimised variant uses a stacked <code>title-group</code> layout (matching the mobile Header variant). This override is applied via <code>.system-role--minimised .header__title-group</code> scoped CSS in <code>SystemRole.css</code> — not added to the Header component itself. This is a Case B contextual override: it is specific to the SystemRole Minimised context and is not a formal Header variant in Figma.</p><h2 id="variants" tabindex="-1">Variants <a class="header-anchor" href="#variants" aria-label="Permalink to &quot;Variants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variant</th><th>Node</th><th>Size</th><th>Padding</th><th>Controls</th><th>Activation</th><th>Notes</th></tr></thead><tbody><tr><td>Default</td><td>163:3894</td><td>1512×973px</td><td>40px all (<code>--ai-spacing-8</code>)</td><td><code>panel-right-dashed</code> + <code>x</code> (40×40px)</td><td>JS <code>.system-role--open</code></td><td>Full-screen modal with blurred backdrop</td></tr><tr><td>Minimised</td><td>169:2466</td><td>400px w × 1360px h</td><td>pt-16 px-24 pb-24</td><td><code>maximize-2</code> + <code>x</code> (32×32px)</td><td>JS <code>.system-role--minimised</code></td><td>Floating compact panel, draggable, left-edge resizable</td></tr><tr><td>Mobile</td><td>176:3242</td><td>Full viewport</td><td>pt-16 px-24 pb-24</td><td><code>panel-right-dashed</code> + <code>x</code> (32×32px)</td><td>CSS <code>@media (max-width: 767px)</code></td><td>Full-viewport CSS-only layout, no resize/drag, no overlay</td></tr></tbody></table><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><h3 id="modal-structure" tabindex="-1">Modal structure <a class="header-anchor" href="#modal-structure" aria-label="Permalink to &quot;Modal structure&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Figma element</th><th>CSS class</th><th>Notes</th></tr></thead><tbody><tr><td>Root modal</td><td><code>.system-role</code></td><td><code>position: fixed</code>, centered via <code>transform: translate(-50%, -50%)</code></td></tr><tr><td>Open state</td><td><code>.system-role--open</code></td><td><code>opacity: 1; pointer-events: auto</code></td></tr><tr><td>Minimised state</td><td><code>.system-role--minimised</code></td><td>Width/padding overrides + layout changes</td></tr><tr><td>Dirty state</td><td><code>.system-role--dirty</code></td><td>Toggles header button group</td></tr><tr><td>No-transition (drag/resize)</td><td><code>.system-role--no-transition</code></td><td><code>transition: none !important</code> — JS adds/removes during drag</td></tr><tr><td>Backdrop overlay</td><td><code>.system-role-overlay</code></td><td><code>position: fixed; inset: 0</code></td></tr><tr><td>Overlay visible</td><td><code>.system-role-overlay--open</code></td><td><code>opacity: 1</code></td></tr><tr><td>Top bar</td><td><code>.system-role__top</code></td><td>Flex row (Default) → flex column (Minimised)</td></tr><tr><td>Window controls</td><td><code>.system-role__controls</code></td><td>Icon button group; <code>order: 1</code> in Default, <code>order: -1</code> in Minimised; <code>width: 100%; max-width: 400px</code> in Default so the controls column aligns with the sidebar below</td></tr><tr><td>Minimize button</td><td><code>.system-role__minimize-btn</code></td><td><code>sidebar</code> icon; hidden in Minimised via CSS</td></tr><tr><td>Maximize button</td><td><code>.system-role__maximize-btn</code></td><td><code>maximize-2</code> icon; hidden in Default via CSS</td></tr><tr><td>Close button</td><td><code>.system-role__close-btn</code></td><td><code>x</code> icon; always visible</td></tr><tr><td>Body</td><td><code>.system-role__body</code></td><td>Flex row (Default) → flex column (Minimised)</td></tr><tr><td>Prompt area</td><td><code>.system-role__prompt</code></td><td><code>flex: 1</code>; bordered with <code>--ai-surface-contrast</code></td></tr><tr><td>Textarea</td><td><code>.system-role__textarea</code></td><td><code>flex: 1</code>; no border/outline</td></tr><tr><td>Sidebar</td><td><code>.system-role__sidebar</code></td><td><code>width: 400px</code> (Default) → <code>width: 100%</code> (Minimised)</td></tr><tr><td>Resize handle (left edge)</td><td><code>.system-role__resize-handle</code></td><td><code>display: none</code> (Default) → <code>display: block</code> (Minimised)</td></tr><tr><td>Resize handle (bottom edge)</td><td><code>.system-role__resize-handle-bottom</code></td><td><code>display: none</code> (Default) → <code>display: block</code> (Minimised); <code>cursor: ns-resize</code></td></tr><tr><td>Textarea resize handle</td><td><code>.system-role__textarea-resize-handle</code></td><td><code>display: none</code> (Default) → <code>display: block</code> (Minimised); sits between textarea and sidebar</td></tr></tbody></table><h3 id="header-button-states" tabindex="-1">Header button states <a class="header-anchor" href="#header-button-states" aria-label="Permalink to &quot;Header button states&quot;">​</a></h3><table tabindex="0"><thead><tr><th>State</th><th>Visible buttons</th><th>CSS rule</th></tr></thead><tbody><tr><td>Clean (default)</td><td><code>.system-role__btn-default</code> (disabled Make Live)</td><td>Base CSS</td></tr><tr><td>Dirty (textarea edited)</td><td><code>.system-role__btn-discard</code> + <code>.system-role__btn-save</code></td><td><code>.system-role--dirty</code> modifier</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>CSS Variable</th><th>Value</th></tr></thead><tbody><tr><td>Modal background</td><td><code>--ai-surface-elevated-1</code></td><td><code>#FFFFFF</code> (light) / <code>#212123</code> (dark)</td></tr><tr><td>Modal border</td><td><code>--ai-border-secondary</code></td><td><code>1px solid</code></td></tr><tr><td>Modal border-radius</td><td><code>--ai-radius-xl</code></td><td><code>1.5rem</code></td></tr><tr><td>Default padding</td><td><code>--ai-spacing-8</code></td><td><code>2.5rem</code> (40px)</td></tr><tr><td>Minimised padding-top</td><td><code>--ai-spacing-5</code></td><td><code>1rem</code> (16px)</td></tr><tr><td>Minimised padding-left/right/bottom</td><td><code>--ai-spacing-6</code></td><td><code>1.5rem</code> (24px)</td></tr><tr><td>Top bar / body gap</td><td><code>--ai-spacing-7</code></td><td><code>2rem</code> (32px) — matches body column gap so header/controls align over prompt/sidebar</td></tr><tr><td>Body gap (prompt ↔ sidebar)</td><td><code>--ai-spacing-7</code></td><td><code>2rem</code> (32px)</td></tr><tr><td>Sidebar panels gap</td><td><code>--ai-spacing-7</code></td><td><code>2rem</code> (32px)</td></tr><tr><td>Prompt border color</td><td><code>--ai-surface-contrast</code></td><td><code>#D1D5DB</code></td></tr><tr><td>Prompt border-radius</td><td><code>--ai-radius-lg</code></td><td><code>1rem</code></td></tr><tr><td>Prompt padding (Default)</td><td><code>--ai-spacing-6</code></td><td><code>1.5rem</code> (24px)</td></tr><tr><td>Prompt padding (Minimised)</td><td><code>--ai-spacing-5</code></td><td><code>1rem</code> (16px) — updated in Figma</td></tr><tr><td>Textarea text</td><td><code>--ai-text-primary</code></td><td><code>#1F2A37</code></td></tr><tr><td>Textarea font-size</td><td><code>--ai-font-fixed-xs</code></td><td><code>0.875rem</code> (14px, fixed — never responsive)</td></tr><tr><td>Textarea line-height</td><td><code>--ai-leading-md</code></td><td><code>1.5rem</code></td></tr><tr><td>Minimised icon btn size</td><td><code>--ai-spacing-7</code></td><td><code>2rem</code> (32px)</td></tr><tr><td>Minimised header btn height</td><td><code>--ai-spacing-7</code></td><td><code>2rem</code> (32px)</td></tr><tr><td>Minimised header btn padding</td><td><code>--ai-spacing-4</code></td><td><code>0.75rem</code> (12px)</td></tr><tr><td>Minimised header btn font</td><td><code>--ai-font-fluid-xxs</code></td><td><code>0.75rem</code></td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Figma value</th><th>Decision</th></tr></thead><tbody><tr><td>Modal box-shadow</td><td><code>--ai-shadow-lg</code></td><td>Resolved — uses shadow token</td></tr><tr><td>Backdrop colour (light)</td><td><code>rgba(27, 27, 31, 0.5)</code></td><td>Approved — Neutral/900 at 50% opacity</td></tr><tr><td>Backdrop colour (dark)</td><td><code>rgba(0, 0, 0, 0.6)</code></td><td>Approved — true black at 60% opacity</td></tr><tr><td>Backdrop blur</td><td>Not specified in tokens</td><td>Approved as <code>blur(2px)</code></td></tr><tr><td>Textarea text colour</td><td>Figma: <code>text-black</code> (<code>#000000</code>)</td><td>Approved substitution: <code>--ai-text-primary</code> for dark mode correctness</td></tr></tbody></table><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The <code>data-layout=&quot;minimised&quot;</code> attribute activates <code>css/tokens-minimised.css</code> which shrinks all <code>--ai-font-fluid-*</code> tokens to their compact values — no per-property overrides needed for fluid typography.</li><li>Box-shadow token gap noted for future Figma work: <code>--ai-shadow-modal</code> or similar.</li><li>Drag and resize use <code>--no-transition</code> class to suppress CSS transitions during pointer events. Transitions resume on <code>mouseup</code>.</li><li>The right edge of the panel stays fixed during left-edge resize (the panel grows leftward).</li><li>On minimise, JS sets <code>modal.style.height = 75vh</code> and <code>textarea.style.height = panelHeight/3</code> to give a concrete starting layout. Both heights are independently resizable afterward.</li><li>On maximise, <code>modal.style.cssText = &#39;&#39;</code> clears all inline styles; <code>textarea.style.height = &#39;&#39;</code> is also cleared so it fills the flex prompt area naturally.</li><li>The bottom resize handle grows the panel downward; sidebar fills remaining body height via <code>flex: 1</code> and scrolls internally.</li><li><strong>Mobile variant (176:3242):</strong> CSS-only — no additional JS. The <code>panel-right-dashed</code> minimize button visible in Default mode is also the correct button for mobile (Figma updated to match). Resize handles, drag, and overlay are suppressed via <code>@media (max-width: 767px)</code>. The modal fills the full viewport and scrolls vertically. Layout mirrors Minimised visually but is activated by screen width rather than a JS class toggle.</li></ul><h2 id="figma" tabindex="-1">Figma <a class="header-anchor" href="#figma" aria-label="Permalink to &quot;Figma&quot;">​</a></h2><p><a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=163-3894" target="_blank" rel="noreferrer">Open in Figma</a></p>',57))])}const x=a(n,[["render",h]]);export{v as __pageData,x as default};
